interface JournalProps {
  onArticleClick: (article: JournalArticle) => void;
  isDarkMode: boolean;
}

const Journal: React.FC<JournalProps> = ({ onArticleClick, isDarkMode }) => {
  const textColor = isDarkMode ? 'text-[#F5F2EB]' : 'text-[#2C2A26]';
