  const borderColor = isDarkMode ? 'border-[#3D3B36]' : 'border-[#D6D1C7]';

  const handleKeyDown = (e: React.KeyboardEvent, article: JournalArticle) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onArticleClick(article);
    }
  };

  return (
    <section id="journal" className={`py-32 px-6 md:px-12 transition-colors duration-500 ${isDarkMode ? 'bg-[#1A1917]' : 'bg-[#F5F2EB]'}`} aria-label="Journal">
