        <div className={`flex flex-col md:flex-row justify-between items-start md:items-end mb-20 pb-8 border-b ${borderColor}`}>
            <div>
                <span className="block text-xs font-bold uppercase tracking-[0.2em] text-[#A8A29E] mb-4">Editorial</span>
                <h2 className={`text-4xl md:text-6xl font-serif ${textColor}`}>The Journal</h2>
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
            {JOURNAL_ARTICLES.map((article) => (
                <article 
                    key={article.id} 
                    className="group cursor-pointer flex flex-col text-left outline-none focus:ring-2 focus:ring-[#E20613] focus:ring-offset-4 rounded-sm"
                    onClick={() => onArticleClick(article)}
                    onKeyDown={(e) => handleKeyDown(e, article)}
                    role="button"
                    tabIndex={0}
                    aria-label={`Read article: ${article.title}`}
                >
                    <div className={`w-full aspect-[4/3] overflow-hidden mb-8 ${isDarkMode ? 'bg-[#121110]' : 'bg-[#EBE7DE]'}`}>
                        <img 
                            src={article.image} 
                            alt="" 
                            className={`w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105 ${isDarkMode ? 'grayscale-[0.5] brightness-75 group-hover:grayscale-0 group-hover:brightness-100' : 'grayscale-[0.2] group-hover:grayscale-0'}`}
                        />
                    </div>
                    <div className="flex flex-col flex-1 text-left">
                        <span className="text-xs font-medium uppercase tracking-widest text-[#A8A29E] mb-3">{article.date}</span>
                        <h3 className={`text-2xl font-serif ${textColor} mb-4 leading-tight group-hover:underline decoration-1 underline-offset-4`}>{article.title}</h3>
                        <p className={`${subTextColor} font-light leading-relaxed`}>{article.excerpt}</p>
                    </div>
                </article>
            ))}
        </div>
      </div>
    </section>
  );
};

export default Journal;

