import React, { useState } from 'react';

interface FooterProps {
  onLinkClick: (e: React.MouseEvent<HTMLAnchorElement>, targetId: string) => void;
  isDarkMode: boolean;
}

const Footer: React.FC<FooterProps> = ({ onLinkClick, isDarkMode }) => {
  const [subscribeStatus, setSubscribeStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [email, setEmail] = useState('');

  const handleSubscribe = () => {
    if (!email) return;
    setSubscribeStatus('loading');
    setTimeout(() => {
      setSubscribeStatus('success');
      setEmail('');
    }, 1500);
  };

  const bgColor = isDarkMode ? 'bg-[#121110]' : 'bg-[#EBE7DE]';
  const textColor = isDarkMode ? 'text-[#F5F2EB]' : 'text-[#2C2A26]';
  const subTextColor = isDarkMode ? 'text-[#A8A29E]' : 'text-[#5D5A53]';
  const borderColor = isDarkMode ? 'border-[#3D3B36]' : 'border-[#D6D1C7]';

  return (
    <footer className={`${bgColor} pt-24 pb-12 px-6 ${subTextColor} transition-colors duration-500`}>
      <div className="max-w-[1800px] mx-auto grid grid-cols-1 md:grid-cols-12 gap-12">

        <div className="md:col-span-4">
          <h4 className={`text-2xl font-serif ${textColor} mb-6`}>Northbrand Collective</h4>
          <p className="max-w-xs font-light leading-relaxed">
