          </p>
        </div>

        <div className="md:col-span-2">
          <h4 className={`font-medium ${textColor} mb-6 tracking-wide text-sm uppercase`}>Directory</h4>
          <ul className="space-y-4 font-light">
            <li><a href="#tools" onClick={(e) => onLinkClick(e, 'tools')} className={`hover:${textColor} transition-colors underline-offset-4 hover:underline focus:outline-none focus:ring-1 focus:ring-[#E20613]`}>All Tools</a></li>
            <li><a href="#tools" onClick={(e) => onLinkClick(e, 'tools')} className={`hover:${textColor} transition-colors underline-offset-4 hover:underline focus:outline-none focus:ring-1 focus:ring-[#E20613]`}>Photography</a></li>
            <li><a href="#tools" onClick={(e) => onLinkClick(e, 'tools')} className={`hover:${textColor} transition-colors underline-offset-4 hover:underline focus:outline-none focus:ring-1 focus:ring-[#E20613]`}>Development</a></li>
            <li><a href="#tools" onClick={(e) => onLinkClick(e, 'tools')} className={`hover:${textColor} transition-colors underline-offset-4 hover:underline focus:outline-none focus:ring-1 focus:ring-[#E20613]`}>Military/VA</a></li>
          </ul>
        </div>

        <div className="md:col-span-2">
          <h4 className={`font-medium ${textColor} mb-6 tracking-wide text-sm uppercase`}>Philosophy</h4>
          <ul className="space-y-4 font-light">
            <li><a href="#about" onClick={(e) => onLinkClick(e, 'about')} className={`hover:${textColor} transition-colors underline-offset-4 hover:underline focus:outline-none focus:ring-1 focus:ring-[#E20613]`}>Our Story</a></li>
            <li><a href="#journal" onClick={(e) => onLinkClick(e, 'journal')} className={`hover:${textColor} transition-colors underline-offset-4 hover:underline focus:outline-none focus:ring-1 focus:ring-[#E20613]`}>Journal</a></li>
            <li><a href="https://www.instagram.com/brondolfr.lo" target="_blank" rel="noreferrer" className={`hover:${textColor} transition-colors underline-offset-4 hover:underline focus:outline-none focus:ring-1 focus:ring-[#E20613]`}>Instagram</a></li>
          </ul>
        </div>

        <div className="md:col-span-4">
          <h4 className={`font-medium ${textColor} mb-6 tracking-wide text-sm uppercase`}>Updates</h4>
          <div className="flex flex-col gap-4">
            <label htmlFor="email-subscribe" className="sr-only">Email Address</label>
            <input 
              id="email-subscribe"
              type="email" 
              placeholder="email@address.com" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              disabled={subscribeStatus === 'loading' || subscribeStatus === 'success'}
              className={`bg-transparent border-b ${borderColor} py-2 text-lg outline-none focus:border-${isDarkMode ? '[#F5F2EB]' : '[#2C2A26]'} transition-colors placeholder-[#A8A29E]/70 ${textColor} disabled:opacity-50 focus:ring-0`} 
              aria-label="Email Address for newsletter"
            />
            <button 
              onClick={handleSubscribe}
              disabled={subscribeStatus !== 'idle' || !email}
              className={`self-start text-sm font-medium uppercase tracking-widest mt-2 hover:${textColor} disabled:cursor-default disabled:hover:${subTextColor} disabled:opacity-50 transition-opacity focus:outline-none focus:ring-2 focus:ring-[#E20613] rounded-sm p-1`}
              aria-live="polite"
            >
              {subscribeStatus === 'idle' && 'Join the list'}
              {subscribeStatus === 'loading' && 'Joining...'}
              {subscribeStatus === 'success' && 'Welcome aboard'}
            </button>
          </div>
        </div>
      </div>

      <div className={`max-w-[1800px] mx-auto mt-20 pt-8 border-t ${borderColor} flex flex-col md:flex-row justify-between items-center text-xs uppercase tracking-widest opacity-60`}>
        <p>Created by Northbrand Collective &copy; 2025</p>
        <p>Abilene, TX</p>
      </div>
    </footer>
  );
};

